    const svg = (name, size = 14) => {
      const raw = ICO[name] || '';
      const attrMatch = raw.match(/<svg([^>]*)>/);
      const origAttrs = attrMatch ? attrMatch[1].replace(/\s*(viewBox|width|height)="[^"]*"/g, '') : '';
      const inner = (raw.match(/<svg[^>]*>([\s\S]*)<\/svg>/) || [, ''])[1];
      return `<svg width="${size}" height="${size}" viewBox="0 0 24 24"${origAttrs} style="display:inline-block;vertical-align:middle;flex-shrink:0">${inner}</svg>`;
    };

